import { useState } from 'react';
import { Briefcase, BookOpen, Landmark, FlameKindling, Globe, Building2, GraduationCap, Award, ExternalLink } from 'lucide-react';
import SectionHeader from './SectionHeader';
import { useApp } from '../context/AppContext';
import t from '../i18n/translations';
import { glass, glassHover } from '../utils/glass';

function getIcon(org, type) {
  if (org.includes('CIB') || org.includes('التجاري')) return Landmark;
  if (org.includes('ASORC') || org.includes('Refining') || org.includes('تكرير')) return FlameKindling;
  if (org.includes('Nile') || org.includes('النيل')) return FlameKindling;
  if (org.includes('Google') || org.includes('Misr') || org.includes('مصر')) return Globe;
  if (org.includes('HSBC')) return Building2;
  if (type === 'internship') return Briefcase;
  return GraduationCap;
}

function getAccent(type) {
  return type === 'internship'
    ? { color: '#f0a500', bg: 'rgba(240,165,0,0.12)', border: 'rgba(240,165,0,0.25)', stripe: 'linear-gradient(90deg,#f0a500,#e8920a)' }
    : { color: '#2a9d8f', bg: 'rgba(42,157,143,0.12)', border: 'rgba(42,157,143,0.25)', stripe: 'linear-gradient(90deg,#2a9d8f,#1f7a6e)' };
}

// Split desc by · into separate topic chips
function DescContent({ desc, dark }) {
  const tMuted = dark ? 'rgba(255,255,255,0.6)' : '#5a5a72';
  const chipBg = dark ? 'rgba(255,255,255,0.06)' : 'rgba(26,26,46,0.05)';
  const chipBorder = dark ? 'rgba(255,255,255,0.10)' : 'rgba(26,26,46,0.10)';

  if (desc && desc.includes('·')) {
    return (
      <div className="flex flex-wrap gap-1.5 mt-3">
        {desc.split('·').map((item, i) => (
          <span key={i}
            className="text-[.72rem] px-2.5 py-1 rounded-lg font-medium"
            style={{ background: chipBg, border: `1px solid ${chipBorder}`, color: tMuted }}>
            {item.trim()}
          </span>
        ))}
      </div>
    );
  }
  return <p className="text-[.85rem] leading-[1.75] mt-3" style={{ color: tMuted }}>{desc}</p>;
}

function ExpCard({ e, dark, lang }) {
  const [hov, setHov] = useState(false);
  const acc   = getAccent(e.type);
  const Icon  = getIcon(e.org, e.type);
  const tBase = dark ? '#f0f0f8' : '#1a1a2e';
  const tMuted = dark ? 'rgba(255,255,255,0.5)' : '#8a8a9a';

  const style = hov
    ? { ...glassHover(dark, acc.color + '30'), transition: 'all .3s' }
    : { ...glass(dark), transition: 'all .3s' };

  return (
    <div
      className="rounded-2xl overflow-hidden cursor-default"
      style={style}
      onMouseEnter={() => setHov(true)}
      onMouseLeave={() => setHov(false)}>
      {/* Top accent stripe */}
      <div className="h-[3px]" style={{ background: acc.stripe }} />

      <div className="p-5">
        <div className="flex items-start gap-3">
          {/* Icon */}
          <div className="w-10 h-10 rounded-xl flex items-center justify-center flex-shrink-0 transition-all"
            style={{ background: acc.bg, border: `1px solid ${acc.border}`, color: acc.color }}>
            <Icon size={18} />
          </div>

          <div className="flex-1 min-w-0">
            {/* Badge + date */}
            <div className="flex items-center gap-2 mb-1 flex-wrap">
              <span className="inline-flex items-center gap-1 text-[.6rem] font-semibold tracking-wider uppercase px-2 py-0.5 rounded-full"
                style={{ background: acc.bg, border: `1px solid ${acc.border}`, color: acc.color }}>
                {e.type === 'internship' ? <><Briefcase size={9}/> {lang === 'ar' ? 'تدريب' : 'Internship'}</> : <><BookOpen size={9}/> {lang === 'ar' ? 'كورس' : 'Training'}</>}
              </span>
              <span className="text-[.65rem] font-medium" style={{ color: tMuted }}>{e.date}</span>
            </div>

            {/* Role */}
            <h3 className="font-semibold text-[.95rem] leading-tight" style={{ color: tBase }}>{e.role}</h3>
            {/* Org */}
            <p className="text-[.78rem] mt-0.5" style={{ color: tMuted }}>{e.org} · {e.location}</p>
          </div>
        </div>

        {/* Description */}
        <DescContent desc={e.desc} dark={dark} />

        {/* Cert link */}
        {e.certImg && (
          <a href={e.certImg} target="_blank" rel="noreferrer"
            className="inline-flex items-center gap-1.5 mt-3 text-[.72rem] font-medium transition-colors"
            style={{ color: acc.color }}>
            <Award size={12} />
            {lang === 'ar' ? 'عرض الشهادة' : 'View Certificate'}
            <ExternalLink size={10} />
          </a>
        )}
      </div>
    </div>
  );
}

export default function Experience() {
  const { dark, lang } = useApp();
  const tr = t[lang];
  const [filter, setFilter] = useState('all');

  const all         = tr.experiences;
  const internships = all.filter(e => e.type === 'internship');
  const trainings   = all.filter(e => e.type === 'training');
  const shown       = filter === 'all' ? all : filter === 'internship' ? internships : trainings;

  const bg = dark ? '#13131e' : '#f5f0e8';
  const fActive   = dark ? { background: '#f0f0f8', color: '#0f0f14' } : { background: '#1a1a2e', color: '#fdfcf9' };
  const fInactive = { ...glass(dark), color: dark ? 'rgba(255,255,255,0.5)' : '#5a5a72' };

  return (
    <section id="experience" style={{ background: bg }} className="py-24 px-[5%] transition-colors duration-300">
      <SectionHeader tag={tr.expTag} title={tr.expTitle} />

      {/* Filters */}
      <div className="flex gap-2 mb-10 flex-wrap">
        {[['all', tr.all, all.length], ['internship', tr.internships, internships.length], ['training', tr.training, trainings.length]].map(([v, l, cnt]) => (
          <button key={v} onClick={() => setFilter(v)}
            className="px-4 py-1.5 rounded-full text-sm font-medium transition-all"
            style={filter === v ? fActive : fInactive}>
            {l} <span className="opacity-50 text-xs ml-1">({cnt})</span>
          </button>
        ))}
      </div>

      <div className="grid md:grid-cols-2 gap-4">
        {shown.map((e, i) => (
          <div key={`${filter}-${i}`} style={{ animation: `fadeUp .4s ${i * 0.06}s ease both` }}>
            <ExpCard e={e} dark={dark} lang={lang} />
          </div>
        ))}
      </div>
    </section>
  );
}
